var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"예? 휴가 말씀이십니까?","JPN":"はい？　休暇ですか？","ENG":"Pardon? A vacation?","TWN":"咦？您是說休假嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그래. 한동안 전술평가로 바쁘게 뛰어다녔으니 자네도 숨 돌릴 여유 정도는 있어야지.","JPN":"そうだ。しばらく戦術評価で忙しく飛び回ってたから、君も息抜きする時間は必要だろう。","ENG":"Yes. You've kept yourself busy with the tactical evaluations for a while. You deserve a break.","TWN":"對。我看你一直為了戰術評估忙得不可開交，是時候休息一下了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"저는 괜찮습니다. 오히려 일을 할 때가 가장 편안합니다.","JPN":"僕は大丈夫です。むしろ仕事をしてる時が一番落ち着きますので。","ENG":"I’m perfectly fine, ma'am. In fact, I feel more rested when I'm working.","TWN":"我沒關係的，反而是工作的時候我最感到安心。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"회의 때도 많이 피곤해 보이더구나, 카일.","JPN":"会議の時もかなり疲れてそうに見えたが、カイル少佐。","ENG":"You seemed exhausted during the meeting, Kyle.","TWN":"但你開會的時候看起來很疲倦啊，凱爾。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"자네 의사는 존중하지만, 과로가 자네의 업무처리에 걸림돌이 되는 건 원치 않아.","JPN":"君の意志は尊重するが、過労が君の業務処理の足手まといになってほしくないんだ。","ENG":"As much as I appreciate your dedication, I wouldn't want fatigue to become an obstacle in your work.","TWN":"我尊重你的想法，但是我不希望過度勞累會妨礙你的工作。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그건...... 컨디션을 제대로 조절하지 못한 제 불찰이군요.","JPN":"それは……体調管理が至らなかった僕の不手際ですね。","ENG":"Well, I... I suppose I have failed to closely monitor my physical well-being.","TWN":"是……沒有調整好狀態確實是我的失誤。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그래. 그러니 일주일만 쉬다 오게. 당분간 부대에는 아무 일 없을 테니 부담 갖지 말고.","JPN":"そうだ。だから一週間だけでいいから休んで来たまえ。\\nしばらくは部隊に何もないと思うから遠慮することはない。","ENG":"That's right. So why don't you take a week off? Don't worry about us. Things will be slow around here for a while.","TWN":"沒錯。所以你就休息一週吧。部隊短時間內沒什麼事，不要太有壓力，好好享受你的假期吧。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"중장님께서 그렇게까지 말씀하신다면...... 알겠습니다.","JPN":"中将がそこまでおっしゃるなら……わかりました。","ENG":"If you say so, ma'am... Very well.","TWN":"既然中將都這麼說了……那我知道了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그래서. 갑자기 생긴 여가시간을 어떻게 보내야 할지 몰라서 나한테 연락했다고?","JPN":"それで、急にもらっちゃった休暇をどう過ごせばいいかわからなくてアタシに連絡したわけ？","ENG":"So... You reached out to me because you couldn't figure out how to spend your free time?","TWN":"所以，你因為不知道如何度過這個突如其來的假期，所以才聯絡我？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"저도 썩 내키진 않았습니다만.","JPN":"僕も気乗りしなかったんですが。","ENG":"Trust me, I wish I had a feasible alternative.","TWN":"雖然我也不是很樂意。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"농땡이를 누구보다 잘 피우는 실비아 씨에게 연락하면 효율적인 조언을 받을 수 있을 것 같아서 말이죠.","JPN":"誰よりもサボり上手なシルビアさんに連絡すれば、効率的なアドバイスをもらえるんじゃないかと思いましたので。","ENG":"But I figured asking for your advice would be the most efficient course of action, having seen how talented you are at slacking off at work.","TWN":"但我想，希爾維亞小姐比任何人都會偷懶，似乎可以幫到我。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"부정은 안 하겠지만 듣는 입장에서 기분이 영 이상하네.","JPN":"否定はしないけど、なんか気に障るわね。","ENG":"I guess I can't deny that, but it's not exactly flattering to hear that either.","TWN":"雖然我不否認這點，但聽到別人這麼說，感覺心情很複雜啊。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"좀 더 부탁하는 사람다운 태도로 말해볼래?","JPN":"もっと誠意を見せてほしいんだけど。","ENG":"Could you rephrase that as someone who needs my help?","TWN":"這就是你拜託別人的態度嗎？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"후, 좋습니다. 원하는 게 있으면 말씀하시죠.","JPN":"ふぅ、いいでしょう。何をお望みですか？","ENG":"*Sigh*... Very well. Please let me know if there's anything you'd like.","TWN":"唉，好吧，妳想要什麼，告訴我吧。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"음~ 최근에 꽤 괜찮은 디저트 카페가 생겼다고 듣긴 했는데 말이지.","JPN":"う～ん実は、最近良さげなデザートが出てくる、いいカフェができたって聞いたんだけど。","ENG":"Hmm... I heard there's a new dessert cafe that's pretty decent.","TWN":"這個嘛～聽說這附近有一家不錯的甜點咖啡廳呢。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"오래 기다리셨습니다. 여왕폐하를 위한 달콤상큼 16종 디저트 세트 대령이오~","JPN":"お待たせしました。女王陛下のための甘くて爽やかなデザート16種セットをお持ちしました～。","ENG":"Thank you for your patience. Here comes the Sweet and Tart 16-piece Dessert Set for Her Majesty!","TWN":"讓您久等了，這是為女王殿下準備的16種甜點套餐～"},"stage":{"bg":"CAFE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"총-★ 총-★","JPN":"ぴょーん★ぴょーん★","ENG":"Ta-da!","TWN":"噠-★ 噠-★"},"stage":{"bg":"CAFE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"오, 가게에 마녀처럼 생긴 직원들만 있어서 별 기대 안 했는데, 퀄리티가 제법이잖아?","JPN":"おぉ、店に魔女コスプレをした店員ばかりいたからあまり期待してなかったんだけど、なかなかクオリティあるわね。","ENG":"Wow, honestly I didn't get my hopes up when I saw all these witch costumes, but this is pretty good!","TWN":"哦，我剛才還因為店員長得都跟魔女一樣，沒什麼多大的期待呢，沒想到服務品質還蠻不錯的嘛？"},"stage":{"bg":"CAFE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"정말 이럴만한 가치가 있는 조언이길 바라겠습니다.","JPN":"こんなところまで連れて来られた以上、本当に価値のあるアドバイスを期待しています。","ENG":"I sincerely hope your advice will be worth all this effort.","TWN":"希望妳的建議有這個價值。"},"stage":{"bg":"CAFE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"에이, 딱딱하게 왜 그러셔? 맛있는 디저트를 즐기는 것도 엄연한 여가활동이라고.","JPN":"まぁまぁ、そんなにお堅くならないで。おいしいデザートを楽しむことも立派な休暇よ。","ENG":"Aw, come on. Loosen up a little! Enjoying a delicious dessert is a part of leisurely activities.","TWN":"哎呀，幹嘛這麼死板啊？享用美味的甜點絕對算得上是種休閒活動。"},"stage":{"bg":"CAFE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L32_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"게다가 나 같은 미녀가 같이 먹어주면 힐링도 두 배로 되지 않겠어?","JPN":"しかも、アタシみたいな美女が一緒に食べてくれると2倍癒されるでしょう？","ENG":"Besides, it's extra rejuvenating if a cutie like me feeds it to you, don't you think?","TWN":"而且還是和我這樣的美女一起享用，療癒效果不就是雙倍嗎？"},"stage":{"bg":"CAFE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"축하 드립니다. 제 속이 안 좋아지도록 하는 게 목적이었다면 성공하셨군요.","JPN":"おめでとうございます。僕の気分を悪くさせるつもりでしたら成功しました。","ENG":"Congratulations. If your objective was to make me feel nauseous, you've succeeded.","TWN":"恭喜妳，如果妳的目的是讓我心情變差，那妳成功了。"},"stage":{"bg":"CAFE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L36_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"이번엔 서점입니까?","JPN":"次は書店ですか？","ENG":"A bookstore this time?","TWN":"這次換書店了嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"마음에 들어? 좋은 책은 정서함양에 도움이 된다고~","JPN":"気に入った？　いい本は心を落ち着かせるのに役立つわよ～。","ENG":"You like it? A good book can do wonders for your state of mind.","TWN":"喜歡嗎？讀本好書有助於豐富涵養喔～"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"나야 딱히 종이책 읽는 취미는 없지만, 너처럼 할아버지 사고를 가진 사람에겐 이런 아날로그 감성이 먹힐 것 같아서 말이야.","JPN":"アタシは別に読書の趣味はないけど、君のように古い考え方を持っている人には、こういうアナログ感性がぴったりだと思うよ。","ENG":"I don't really read paper books all that much, but I figured a guy with the mental age of a grandpa would appreciate the more analog feeling here.","TWN":"雖然我沒有閱讀紙本書的興趣，但感覺像你這種老頭思想的傢伙應該會喜歡吧。"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"......확실히, 책에서 나는 은은한 나무향은 마음을 편하게 해주긴 합니다.","JPN":"……たしかに、本のほのかな木のにおいは心を落ち着かせる効果があります。","ENG":"Indeed... the subtle wooden scent from the book is quite soothing.","TWN":"……確實，書香的確讓人心靈平靜。"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"하지만 이 코너의 근거 없는 공상들로 가득한 소설들은 제 취향에 맞지 않는군요.","JPN":"しかし、このコーナーにある根拠もない空想ばかりの小説は僕の好みじゃありません。","ENG":"However, these novels rife with fictitious imagination don't really appeal to my tastes.","TWN":"但我並不喜歡毫無根據的幻想小說。"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L43_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"이 시집들은 어때? 너 같은 고철로봇에게도 감수성이라는 생명력을 불어넣어주는 마법의 책이라고.","JPN":"この詩集はどう？　アンタみたいなジャンクロボに感受性という生命力を吹き込んでくれる魔法の本なのよ。","ENG":"How about these poetry collections? These are magic books that can blow life into even tinmen like you.","TWN":"這本詩集怎麼樣？就算你的感性思維和故障的機器人一樣，這本魔法書也能帶給你感性的生命力喔。"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"실비아 씨에게 그런 말을 들으니 몹시 불쾌하긴 하지만......","JPN":"シルビアさんにそんなことを言われると、とても不愉快ですが……","ENG":"As offensive it is to hear that coming from you...","TWN":"雖然聽到希爾維亞小姐說出這種話，我感到很不愉快……"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"저도 감수성이 부족하단 얘긴 여러 번 들었습니다.","JPN":"感受性に乏しいと、何度も言われたことも事実です。","ENG":"I have indeed heard that I am rather robotic at times.","TWN":"不過確實有很多人說過我缺乏感性。"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"이 참에 몇 권 사두는 것도 좋겠군요.","JPN":"この際に何冊か買っておいてもいいでしょう。","ENG":"Perhaps I'll buy several copies on this occasion.","TWN":"就趁這個機會買個幾本吧。"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L49_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"다른 건 몰라도, 이건 따지고 넘어가야겠습니다.","JPN":"他のことはさておき、これだけははっきりしておきたいのです。","ENG":"That's it. I'm going to have to confront you this time.","TWN":"不過別的先不管，有件事我得確認一下。"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"실비아 씨는 저를 어린애 취급하시는 겁니까?","JPN":"シルビアさんは、僕のことを子供扱いしてるんですか？","ENG":"Why are you treating me like a child?","TWN":"希爾維亞小姐是不是把我當成小孩了？"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"왜 그래? 장난감 가게에 어린애만 오라는 법은 없잖아?","JPN":"どうしたの？　大人だっておもちゃ屋に行きたくなるものよ。","ENG":"What's wrong? You don't have to be a kid to come to a toy store.","TWN":"怎麼了？誰規定玩具店只有小孩子才能來？"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"만화책도 볼 수 있고. 수집욕구를 자극하는 것들도 꽤 많다고.","JPN":"漫画も読めるし、収集欲をくすぐる物も多いしね。","ENG":"They've even got comic books here. And lots of collectibles that are irresistible.","TWN":"這裡不僅能看漫畫，還有很多能刺激收集欲望的東西喔。"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"예를 들어서 이런 귀여운 깡통로봇 인형이라거나?","JPN":"例えば、こんな可愛いブリキロボットとか？","ENG":"For instance, this adorable tinman doll, you know?","TWN":"比如說這個可愛的罐頭機器人玩偶？"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"음?","JPN":"うん？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"이건......","JPN":"これは……","ENG":"This is...","TWN":"這……"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"왜? 뭔데?","JPN":"何？　何かあるの？","ENG":"What’s up? What is it?","TWN":"怎麼了？那是什麼？"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"오, 카운터즈 카드잖아? 이걸 아직도 팔고 있었구나.","JPN":"お、カウンターカードね。まだ販売してたんだ。","ENG":"Ooh, Counters cards? I didn't know they still sold these.","TWN":"哦，這不是制裁者卡片嗎？居然還有在賣啊。"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"카운터에 대한 세간의 부정적인 인식을 개선하기 위해서 세계의 인지도 있는 카운터들 초상을 모아 만든 트레이딩 카드지.","JPN":"カウンターに対する世間のネガティブな認識を改善するために、\\n世界中の有名なカウンターたちの写真を集めて作ったトレーディングカードよ。","ENG":"They made these trading cards to improve the negative image of Counters among the public. It's got the portraits of some of the most well-known Counters from all over the world.","TWN":"這卡片是為了改變人們對制裁者的負面印象，收集了世界上知名的制裁者肖像做成的。"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"뭐, 카일 너처럼 재미없는 애는 당연히 이런 게 있는 줄도 모르고 살았겠지만~","JPN":"まぁ、カイルみたいにつまらない子供はこのカードの存在を知らないまま生きてきたんと思うけど～。","ENG":"Then again, I guess a boring kid like you never even knew such things existed...","TWN":"不過，像你這種無趣的小孩，活到現在一定連聽都沒聽說過吧～"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"요즘은 하트베리 시리즈가 꽤 인기가 좋은가 보네......","JPN":"最近はハートベリーシリーズがかなり人気みたいね……","ENG":"Looks like the HRT Berry series is quite popular these days.","TWN":"看來最近愛心莓果系列很受歡迎呢……"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"좀 의외네? 네가 트레이딩 카드 같은 걸 다 사고 말이야.","JPN":"ちょっと意外かも？　アンタがトレーディングカードなんか買うなんて。","ENG":"Well, that's a surprise. I never knew you of all people would buy trading cards.","TWN":"有點意外呢，你把訓練卡之類的都買下來了啊。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"넌 당연히 ‘그림카드 같은 무가치한 종이조각을 수집하며 돈을 낭비할 생각은 없습니다.’","JPN":"アンタはてっきり「カードみたいな価値のない紙切れを収集するためにお金を無駄に使う気はありません。」","ENG":"I figured you'd just say \\"I wish not to waste my finances collecting such meaningless pieces of paper with no absolute value.\\"","TWN":"“我不想把錢浪費在收集這些毫無價值的卡片。”"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"라고 할 줄 알았는데 말이야.","JPN":"とか言っちゃいそうだったから。","ENG":"Or something like that.","TWN":"我本來以為你會這麼說呢。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그 말이 맞습니다.","JPN":"その通りです。","ENG":"You are precisely right.","TWN":"妳說的沒錯。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"다만, 잠깐 예전 추억이 떠올라서 충동적인 지출을 했을 뿐이죠.","JPN":"ただ、ちょっとだけ昔のことを思い出して衝動買いしただけです。","ENG":"However, I did make a spontaneous purchase as I was reminded of a bygone memory.","TWN":"我只是突然想起了以前的事情，一時衝動買下而已。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"한 번 뜯어봐. 좋은 카드가 나올지 궁금하지 않아? 내 얼굴이 나올지도?","JPN":"開けてみてよ。いいカードが出るんじゃないかって気になるわよね？　アタシが出てくるかも？","ENG":"Why don't you open it? Aren't you curious what cards you'll get? You might even get me!","TWN":"打開一個看看。說不定會開出一張好卡喔？搞不好是我的肖像呢。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"아뇨. 굳이 이걸 뜯진 않을 겁니다.","JPN":"いいえ。あえてこれを開封したりはしません。","ENG":"No. There's no need for me to open this.","TWN":"不。沒必要打開。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"응? 팩을 샀으면 당연히 뜯어야지, 그게 무슨 소리야?","JPN":"え？　パックを買ったら開けて当然でしょう？　どういうこと？","ENG":"Huh? Card packs are meant to be opened. What are you talking about?","TWN":"嗯？你在說什麼，買卡包當然要打開啊？"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"어차피 제가 찾고 있는 건 이 안에 없습니다.","JPN":"どうせ僕が求めるものはこの中にありません。","ENG":"What I'm looking for is not in here anyway.","TWN":"反正我想要的卡片肯定不在裡面。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"이젠 더 이상 그런 걸 구하기 위해서 욕심을 낼 필요도 없고 말입니다.","JPN":"もうこれ以上、わざわざそんなものを探し回る必要もなくなりました。","ENG":"There's no longer any need for me to desire such cards either.","TWN":"現在也沒有必要去找那張卡了。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그러니까, 왜 그런 욕심을 낼 필요가 없는 거냐니깐?","JPN":"だから、どうしてそんな必要がなくなったの？","ENG":"Why not exactly? I'm not sure I follow.","TWN":"所以說，為什麼你覺得沒有必要了？"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"한때 동경하던 카드 속의 인물을, 지금은 누구보다 가까이에서 모실 수 있게 됐으니까요.","JPN":"かつて憧れてたカードの中の人物を、今はすぐそばで補佐するようになりましたので。","ENG":"I now get to serve the person I admired the most in the cards... in person.","TWN":"因為我以前憧憬的卡片人物，現在就在我身邊。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L30_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"......엥?","JPN":"……えぇ？","ENG":"Huh?","TWN":"……嗯？"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L31_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"너 설마, 나한테 그런 마음을 갖고 있었던 거야?","JPN":"アンタ、もしかしてアタシにそういう気持ちを抱いていたの？","ENG":"Have you really been feeling that way about me?","TWN":"難道說你，對我有那種想法嗎？"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L32_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"비웃음조차 안 나오는군요. 제가 실비아 씨 같은 철부지를 동경할 리 없잖습니까?","JPN":"笑えませんね。僕がシルビアさんのような世間知らずに憧れるわけないでしょう？","ENG":"I can't even bring myself to scoff at that. Why would I ever admire an immature mess like you?","TWN":"我連嘲笑妳的力氣都沒有了。我怎麼可能會憧憬希爾維亞小姐這種不明事理的人？"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"자의식 과잉에 척도가 있다면, 실비아 씨는 틀림없는 중증말기로군요.","JPN":"自意識過剰に目安があるとしたら、シルビアさんはきっと末期だと思います。","ENG":"If self-conceitedness was a disease, your case must be terminal.","TWN":"如果自我意識過剩是種病，那麼希爾維亞小姐毫無疑問，已經是重症末期了。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아님 말던지.","JPN":"どうでもいいけど。","ENG":"Fine, I guess not.","TWN":"不是就算了。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그래서, 오늘 어땠어? 내 덕분에 하루가 평생 기억에 남을 만큼 즐거웠겠지?","JPN":"で、今日はどうだった？　アタシのおかげで一生記憶に残るほど楽しかったわよね？","ENG":"So how did you like your day? I'm sure you'll treasure it forever as the happiest day of your life thanks to me, right?","TWN":"所以，今天過得怎麼樣？托我的福，感受到前所未有的快樂了吧？"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"글쎄요. 중요한 건 결국 여가에 대한 도움이 될만한 정보는 얻지 못했다는 것이죠.","JPN":"さあ。結局休暇についてのアドバイスをもらえなかったんですけどね。","ENG":"I wouldn't be so sure. What's important is that I never learned anything that would help me better spend my leisurely time.","TWN":"確實。重要的是，今天並沒有得到任何有關於假期的有用情報。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"하지만 실비아 씨를 탓할 생각은 없습니다.","JPN":"ですが、シルビアさんを責める気はありません。","ENG":"However, I do not intend to blame you at all.","TWN":"但我不會怪希爾維亞小姐。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"애초에 컴퓨터에 매달려 사는 사람을 데려다 여가활동을 가르쳐달라고 한 제 잘못이 크니까요.","JPN":"そもそもパソコン一筋の人に休暇の過ごし方を教えてほしいと頼んだ僕が悪いんです。","ENG":"The fault is mine for asking for help on leisurely activities from someone who spends the entire day on the computer.","TWN":"讓一個整天待在電腦前的人教我如何度過假期，這是我的重大失誤。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아~ 그러셔?","JPN":"あ～そう。","ENG":"Oh, is that right?","TWN":"啊～是嗎？"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그래도......","JPN":"ですが……","ENG":"Still...","TWN":"但是……"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"어느 정도 즐거웠다는 점은 인정하겠습니다.","JPN":"ある程度楽しかったことは認めます。","ENG":"I'll admit it was somewhat enjoyable.","TWN":"但我承認，某種程度上確實很有趣。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"오, 그것 봐. 그렇게 솔직해지니까 좋잖아?","JPN":"お、そうでしょう？　そうやって素直になれればいいじゃない。","ENG":"Ah, see? Isn't it nice to be honest for a change?","TWN":"哦，你看。坦率點多好啊？"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"물론 그만한 지출을 했는데도, 즐겁지 않다면 그게 오히려 이상한 거겠지만 말이죠.","JPN":"それに僕がそれなりのお金を払いましたので、楽しくなかったら困ります。","ENG":"Frankly, it would be tragic if I didn't enjoy myself even one bit after spending that much money.","TWN":"當然，花了這麼多錢還不愉快的話，反而有點奇怪了。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"야! 일부러 그러는 거지? 칭찬이든 욕이든 하나만 하라고!","JPN":"こら！わざと言ってるでしょ？　褒めるのか貶すのかどっちかにして！","ENG":"Hey! Now you're just doing that on purpose, right? Either compliment me or yell at me, but make up your mind already!","TWN":"喂！你是故意的嗎？你到底是在誇我還是在損我啊！"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};